import React, { useState } from 'react';

const App = () => {
  const [categories, setCategories] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [drafts, setDrafts] = useState([]);

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex flex-col">
      <div className=" bg-[#C06C88] p-4 flex items-center justify-center">
        <input
          type="search"
          className="bg-transparent p-2 w-full"
          placeholder="Search"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
        <button
          className="bg-[#411C56] p-2 w-20 text-white hover:bg-[#411C56]">
          Search
        </button>
      </div>
      <div className="bg-[#B7D7CD] p-4 flex items-center justify-center mt-4">
        <button
          className="bg-[#411C56] p-2 w-20 text-white hover:bg-[#411C56]">
          Create New Draft
        </button>
      </div>
      <div className="bg-[#090a0f] p-4 flex items-center justify-center mt-4">
        <ul className="list-none p-0 m-0 w-full">
          {categories.map((category, index) => (
            <li key={index} className="bg-[#B7D7CD] p-2 mb-2 w-full">
              {category.name}
            </li>
          ))}
        </ul>
        <ul className="list-none p-0 m-0 w-full">
          {drafts.map((draft, index) => (
            <li key={index} className="bg-[#C06C88] p-2 mb-2 w-full">
              {draft.name}
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
};

export default App;
